/* Pre-baked Nickel Bridge DS bundle for standalone export. Requires React + Babel globals. */
window.NickelBridge = window.NickelBridge || {};
var __NB_MODULES = [{"p":"components/brand/BridgeMark.jsx","names":["BridgeMark"],"src":"/* The two brand marks. variant=\"glyph\" (header) | \"footer\" (colophon) | \"scene\" (splash only). */\nfunction BridgeMark({variant='glyph', width, sceneSrc='assets/bridge-river-scene.svg', style}) {\n  if (variant==='footer') return (\n    <svg width={width||180} height={Math.round((width||180)*46/320)} viewBox=\"0 0 320 46\" style={style}><g stroke=\"var(--verdigris,#6F8F68)\" fill=\"none\"><line x1=\"0\" y1=\"5\" x2=\"320\" y2=\"5\" strokeWidth=\"5\"/><path d=\"M12 40 Q60 16 108 40 Q156 16 204 40 Q252 16 300 40\" strokeWidth=\"3.5\"/><line x1=\"12\" y1=\"5\" x2=\"12\" y2=\"40\" strokeWidth=\"3.5\"/><line x1=\"108\" y1=\"5\" x2=\"108\" y2=\"40\" strokeWidth=\"3.5\"/><line x1=\"204\" y1=\"5\" x2=\"204\" y2=\"40\" strokeWidth=\"3.5\"/><line x1=\"300\" y1=\"5\" x2=\"300\" y2=\"40\" strokeWidth=\"3.5\"/><line x1=\"60\" y1=\"5\" x2=\"60\" y2=\"28\" strokeWidth=\"2\"/><line x1=\"156\" y1=\"5\" x2=\"156\" y2=\"28\" strokeWidth=\"2\"/><line x1=\"252\" y1=\"5\" x2=\"252\" y2=\"28\" strokeWidth=\"2\"/></g></svg>\n  );\n  if (variant==='scene') return <img src={sceneSrc} width={width||390} style={style} alt=\"\"/>;\n  return (\n    <svg width={width||26} height={Math.round((width||26)*122/160)} viewBox=\"0 0 160 122\" style={style}><g stroke=\"var(--verdigris,#6F8F68)\" fill=\"none\"><line x1=\"0\" y1=\"10\" x2=\"160\" y2=\"10\" strokeWidth=\"14\"/><path d=\"M8 112 Q80 38 152 112\" strokeWidth=\"10\"/><line x1=\"8\" y1=\"10\" x2=\"8\" y2=\"112\" strokeWidth=\"10\"/><line x1=\"152\" y1=\"10\" x2=\"152\" y2=\"112\" strokeWidth=\"10\"/><line x1=\"80\" y1=\"10\" x2=\"80\" y2=\"75\" strokeWidth=\"7\"/></g></svg>\n  );\n}"},{"p":"components/brand/TicketStub.jsx","names":["TicketStub"],"src":"/* Ticket-stub counter (approved 1k). Solid box, dashed perforation, rotated edge text. */\nfunction TicketStub({label='BOARD', value='No. 2 of 4', edgeText='ADMIT ONE', width=184, style}) {\n  const h = Math.round(width*66/184);\n  return (\n    <svg width={width} height={h} viewBox=\"0 0 184 66\" style={style}>\n      <rect x=\"2\" y=\"2\" width=\"180\" height=\"62\" fill=\"var(--panel,#fff)\" stroke=\"var(--ink,#141414)\" strokeWidth=\"3\"/>\n      <line x1=\"126\" y1=\"2\" x2=\"126\" y2=\"64\" stroke=\"var(--ink,#141414)\" strokeWidth=\"2\" strokeDasharray=\"3 5\"/>\n      <text x=\"16\" y=\"26\" fontFamily=\"Besley,serif\" fontWeight=\"700\" fontSize=\"11\" letterSpacing=\"3\" fill=\"var(--ink,#141414)\">{label}</text>\n      <text x=\"16\" y=\"52\" fontFamily=\"Besley,serif\" fontWeight=\"800\" fontSize=\"24\" fill=\"var(--ink,#141414)\">{value}</text>\n      <text x=\"146\" y=\"14\" fontFamily=\"Besley,serif\" fontWeight=\"700\" fontSize=\"10\" letterSpacing=\"2\" fill=\"var(--ink,#141414)\" transform=\"rotate(90 146 14)\">{edgeText}</text>\n    </svg>\n  );\n}"},{"p":"components/brand/FlipDigits.jsx","names":["FlipDigits"],"src":"/* Flip-digit numerals (approved 1m) — turnstile counter for hero numbers only. */\nfunction FlipDigits({value='58', suffix='%', size=44, style}) {\n  const w = Math.round(size*30/44), fs = Math.round(size*26/44), sfs = Math.round(size*22/44);\n  const cell = {width:w, height:size, fontFamily:'Besley,serif', fontWeight:800, display:'flex', alignItems:'center', justifyContent:'center', borderRadius:3, position:'relative', overflow:'hidden'};\n  return (\n    <div style={{display:'flex', gap:3, ...style}}>\n      {String(value).split('').map((ch,i)=>(\n        <div key={i} style={{...cell, background:'var(--ink,#141414)', color:'#fff', fontSize:fs}}>\n          {ch}\n          <div style={{position:'absolute', left:0, right:0, top:'50%', height:1.5, background:'rgba(255,255,255,.35)'}}/>\n        </div>\n      ))}\n      {suffix ? <div style={{...cell, background:'#fff', color:'var(--ink,#141414)', border:'2px solid var(--ink,#141414)', fontSize:sfs, boxSizing:'border-box'}}>{suffix}</div> : null}\n    </div>\n  );\n}"},{"p":"components/brand/InkStamp.jsx","names":["InkStamp"],"src":"/* Oval ink stamp (approved treatment for statuses). Rotation + ink-fade mask are mandatory. */\nfunction InkStamp({children='SCORED', color='var(--ink)', rotate=-5, fade='right', size=10, style}) {\n  const mask = fade==='left'\n    ? 'linear-gradient(75deg,rgba(0,0,0,.55) 0%,#000 45%)'\n    : 'linear-gradient(105deg,#000 50%,rgba(0,0,0,.45) 100%)';\n  return (\n    <div style={{display:'inline-block', border:'2px solid '+color, borderRadius:'50%', padding:'4px '+Math.round(size*1.1)+'px', transform:'rotate('+rotate+'deg)', WebkitMaskImage:mask, maskImage:mask, ...style}}>\n      <span style={{fontFamily:'\"Josefin Sans\",sans-serif', fontWeight:600, fontSize:size, letterSpacing:'.22em', color}}>{children}</span>\n    </div>\n  );\n}"},{"p":"components/brand/Postmark.jsx","names":["Postmark"],"src":"/* Circular postmark + wave cancel (approved 3b). Result screens only. */\nfunction Postmark({arcTop='NICKEL BRIDGE', arcBottom='BOARD 2 · TOLL PAID', line1='SCORED', line2='JUL 13 1926', size=104, style}) {\n  const l1fs = String(line1).length > 6 ? 12 : 13;\n  const id = React.useId ? React.useId().replace(/[:]/g,'') : Math.random().toString(36).slice(2);\n  return (\n    <div style={{display:'flex', alignItems:'center', transform:'rotate(-4deg)', WebkitMaskImage:'linear-gradient(100deg,#000 50%,rgba(0,0,0,.4) 100%)', maskImage:'linear-gradient(100deg,#000 50%,rgba(0,0,0,.4) 100%)', ...style}}>\n      <svg width={size} height={size} viewBox=\"0 0 104 104\">\n        <circle cx=\"52\" cy=\"52\" r=\"49\" fill=\"none\" stroke=\"var(--ink,#141414)\" strokeWidth=\"3\"/>\n        <circle cx=\"52\" cy=\"52\" r=\"36\" fill=\"none\" stroke=\"var(--ink,#141414)\" strokeWidth=\"1.5\"/>\n        <defs><path id={'pmT'+id} d=\"M 14 52 A 38 38 0 0 1 90 52\"/><path id={'pmB'+id} d=\"M 12 52 A 40 40 0 0 0 92 52\"/></defs>\n        <text fontFamily='\"Josefin Sans\",sans-serif' fontWeight=\"600\" fontSize=\"10.5\" letterSpacing=\"2.5\" fill=\"var(--ink,#141414)\"><textPath href={'#pmT'+id} startOffset=\"50%\" textAnchor=\"middle\">{arcTop}</textPath></text>\n        <text fontFamily='\"Josefin Sans\",sans-serif' fontWeight=\"600\" fontSize=\"8.5\" letterSpacing=\"2\" fill=\"var(--ink,#141414)\"><textPath href={'#pmB'+id} startOffset=\"50%\" textAnchor=\"middle\">{arcBottom}</textPath></text>\n        <text x=\"52\" y=\"49\" textAnchor=\"middle\" fontFamily='\"Josefin Sans\",sans-serif' fontWeight=\"600\" fontSize={l1fs} letterSpacing=\"1\" fill=\"var(--ink,#141414)\">{line1}</text>\n        <text x=\"52\" y=\"63\" textAnchor=\"middle\" fontFamily='\"Crimson Pro\",serif' fontSize=\"10\" fill=\"var(--ink,#141414)\">{line2}</text>\n      </svg>\n      <svg width={Math.round(size*0.62)} height={Math.round(size*0.58)} viewBox=\"0 0 64 60\" style={{marginLeft:-8}}>\n        <g stroke=\"var(--ink,#141414)\" strokeWidth=\"2.5\" fill=\"none\"><path d=\"M0 8 Q16 2 32 8 T64 8\"/><path d=\"M0 22 Q16 16 32 22 T64 22\"/><path d=\"M0 36 Q16 30 32 36 T64 36\"/><path d=\"M0 50 Q16 44 32 50 T64 50\"/></g>\n      </svg>\n    </div>\n  );\n}"},{"p":"components/brand/PerforatedPanel.jsx","names":["PerforatedPanel"],"src":"/* Perforated panel (approved 1n) — the base \"card\"; dashed tear line inside the left edge. */\nfunction PerforatedPanel({children, heading, dashed=false, padding='12px 14px 12px 20px', style}) {\n  const border = dashed ? '1px dashed var(--line-dashed,#B9B4A9)' : '1px solid var(--ink,#141414)';\n  return (\n    <div style={{border, background:'var(--panel,#fff)', position:'relative', padding, color:dashed?'var(--muted)':undefined, ...style}}>\n      <div style={{position:'absolute', left:7, top:0, bottom:0, borderLeft:'1.5px dashed '+(dashed?'var(--line-dashed,#B9B4A9)':'var(--ink,#141414)')}}/>\n      {heading ? <div style={{fontFamily:'Besley,serif', fontWeight:700, fontSize:10, letterSpacing:'.16em', color:'var(--muted,#6E6A62)', marginBottom:8}}>{heading}</div> : null}\n      {children}\n    </div>\n  );\n}"},{"p":"components/core/Button.jsx","names":["Button"],"src":"/* Primary = ink slab, Besley 800 tracked caps, trailing arrow supplied by caller. */\nfunction Button({children, variant='primary', disabled=false, onClick, style}) {\n  const base = {display:'block', width:'100%', textAlign:'center', fontFamily:'Besley,serif', letterSpacing:'.06em', borderRadius:2, cursor:disabled?'default':'pointer', boxSizing:'border-box', opacity:disabled?0.4:1, userSelect:'none'};\n  const kind = variant==='primary'\n    ? {background:'var(--ink,#141414)', color:'#fff', fontWeight:800, fontSize:15, padding:13, border:'none'}\n    : {background:'var(--panel,#fff)', color:'var(--ink,#141414)', fontWeight:700, fontSize:13, padding:11, border:'1px solid var(--ink,#141414)'};\n  return <div role=\"button\" aria-disabled={disabled} onClick={disabled?undefined:onClick} style={{...base, ...kind, ...style}}>{children}</div>;\n}"},{"p":"components/core/Chip.jsx","names":["Chip"],"src":"/* Fact chip (HCP ranges, constraints). solid = 1px ink; quiet = gray, muted. */\nfunction Chip({children, quiet=false, color, style}) {\n  return <span style={{display:'inline-block', border:'1px solid '+(color||(quiet?'var(--line,#D8D5CE)':'var(--ink,#141414)')), color:color||(quiet?'var(--muted,#6E6A62)':'var(--ink,#141414)'), fontFamily:'Besley,serif', fontWeight:quiet?600:700, fontSize:11, padding:'3px 8px', borderRadius:3, ...style}}>{children}</span>;\n}"},{"p":"components/core/Input.jsx","names":["Input"],"src":"function Input({label, value, defaultValue, placeholder, onChange, type='text', style}) {\n  return (\n    <label style={{display:'flex', flexDirection:'column', gap:6, ...style}}>\n      {label ? <span style={{fontFamily:'Besley,serif', fontWeight:700, fontSize:10, letterSpacing:'.2em', color:'var(--muted,#6E6A62)', textTransform:'uppercase'}}>{label}</span> : null}\n      <input type={type} value={value} defaultValue={defaultValue} placeholder={placeholder} onChange={onChange}\n        style={{fontFamily:'\"Crimson Pro\",serif', fontSize:16, color:'var(--ink,#141414)', background:'var(--panel,#fff)', border:'1px solid var(--ink,#141414)', borderRadius:0, padding:'10px 12px', outline:'none', boxSizing:'border-box', width:'100%'}}/>\n    </label>\n  );\n}"},{"p":"components/core/Select.jsx","names":["Select"],"src":"function Select({label, value, defaultValue, onChange, options=[], style}) {\n  return (\n    <label style={{display:'flex', flexDirection:'column', gap:6, ...style}}>\n      {label ? <span style={{fontFamily:'Besley,serif', fontWeight:700, fontSize:10, letterSpacing:'.2em', color:'var(--muted,#6E6A62)', textTransform:'uppercase'}}>{label}</span> : null}\n      <select value={value} defaultValue={defaultValue} onChange={onChange}\n        style={{fontFamily:'\"Crimson Pro\",serif', fontSize:16, color:'var(--ink,#141414)', background:'var(--panel,#fff)', border:'1px solid var(--ink,#141414)', borderRadius:0, padding:'10px 12px', outline:'none', appearance:'none', backgroundImage:'linear-gradient(45deg,transparent 50%,#141414 50%),linear-gradient(135deg,#141414 50%,transparent 50%)', backgroundPosition:'calc(100% - 18px) 50%,calc(100% - 12px) 50%', backgroundSize:'6px 6px', backgroundRepeat:'no-repeat'}}>\n        {options.map(o=><option key={o} value={o}>{o}</option>)}\n      </select>\n    </label>\n  );\n}"},{"p":"components/core/Checkbox.jsx","names":["Checkbox"],"src":"function Checkbox({label, checked, defaultChecked, onChange, style}) {\n  const [on, setOn] = React.useState(!!defaultChecked);\n  const isOn = checked!==undefined ? checked : on;\n  return (\n    <label onClick={()=>{ if(checked===undefined) setOn(!on); onChange && onChange(!isOn); }} style={{display:'inline-flex', alignItems:'center', gap:10, cursor:'pointer', ...style}}>\n      <span style={{width:18, height:18, border:'1.5px solid var(--ink,#141414)', background:isOn?'var(--ink,#141414)':'var(--panel,#fff)', display:'inline-flex', alignItems:'center', justifyContent:'center', color:'#fff', fontSize:12, fontWeight:700, boxSizing:'border-box'}}>{isOn?'✓':''}</span>\n      <span style={{fontFamily:'\"Crimson Pro\",serif', fontSize:15, color:'var(--ink,#141414)'}}>{label}</span>\n    </label>\n  );\n}"},{"p":"components/core/Radio.jsx","names":["Radio"],"src":"function Radio({options=[], value, defaultValue, onChange, style}) {\n  const [val, setVal] = React.useState(defaultValue);\n  const cur = value!==undefined ? value : val;\n  return (\n    <div style={{display:'flex', flexDirection:'column', gap:8, ...style}}>\n      {options.map(o=>(\n        <label key={o} onClick={()=>{ if(value===undefined) setVal(o); onChange && onChange(o); }} style={{display:'inline-flex', alignItems:'center', gap:10, cursor:'pointer'}}>\n          <span style={{width:18, height:18, borderRadius:'50%', border:'1.5px solid var(--ink,#141414)', display:'inline-flex', alignItems:'center', justifyContent:'center', boxSizing:'border-box'}}>{cur===o ? <span style={{width:9, height:9, borderRadius:'50%', background:'var(--ink,#141414)'}}/> : null}</span>\n          <span style={{fontFamily:'\"Crimson Pro\",serif', fontSize:15, color:'var(--ink,#141414)'}}>{o}</span>\n        </label>\n      ))}\n    </div>\n  );\n}"},{"p":"components/core/Switch.jsx","names":["Switch"],"src":"function Switch({label, checked, defaultChecked, onChange, style}) {\n  const [on, setOn] = React.useState(!!defaultChecked);\n  const isOn = checked!==undefined ? checked : on;\n  return (\n    <label onClick={()=>{ if(checked===undefined) setOn(!on); onChange && onChange(!isOn); }} style={{display:'inline-flex', alignItems:'center', gap:10, cursor:'pointer', ...style}}>\n      <span style={{width:38, height:20, border:'1.5px solid var(--ink,#141414)', background:isOn?'var(--ink,#141414)':'var(--panel,#fff)', position:'relative', boxSizing:'border-box', transition:'background .15s'}}>\n        <span style={{position:'absolute', top:2, left:isOn?19:2, width:13, height:13, background:isOn?'#fff':'var(--ink,#141414)', transition:'left .15s'}}/>\n      </span>\n      <span style={{fontFamily:'\"Crimson Pro\",serif', fontSize:15, color:'var(--ink,#141414)'}}>{label}</span>\n    </label>\n  );\n}"},{"p":"components/core/Dialog.jsx","names":["Dialog"],"src":"/* Bottom sheet over a scrim — matches the approved call-inspector treatment. */\nfunction Dialog({open=true, title, onClose, children, footer, style}) {\n  if (!open) return null;\n  return (\n    <div style={{position:'absolute', inset:0, zIndex:10}}>\n      <div onClick={onClose} style={{position:'absolute', inset:0, background:'rgba(20,20,20,.34)'}}/>\n      <div style={{position:'absolute', left:0, right:0, bottom:0, background:'#fff', borderTop:'2px solid var(--ink,#141414)', padding:'10px 16px 18px', ...style}}>\n        <div style={{width:40, height:4, background:'var(--line,#D8D5CE)', borderRadius:2, margin:'0 auto 12px'}}/>\n        <div style={{display:'flex', alignItems:'baseline', justifyContent:'space-between'}}>\n          <div style={{fontFamily:'Besley,serif', fontWeight:800, fontSize:19, color:'var(--ink,#141414)'}}>{title}</div>\n          <div onClick={onClose} style={{fontFamily:'Besley,serif', fontWeight:700, fontSize:16, color:'var(--muted,#6E6A62)', cursor:'pointer'}}>✕</div>\n        </div>\n        <div style={{fontFamily:'\"Crimson Pro\",serif', color:'var(--ink,#141414)'}}>{children}</div>\n        {footer}\n      </div>\n    </div>\n  );\n}"},{"p":"components/core/Toast.jsx","names":["Toast"],"src":"/* Ticket-style toast; slides up from the bottom. */\nfunction Toast({children, stamp, open=true, style}) {\n  if (!open) return null;\n  return (\n    <div style={{display:'flex', alignItems:'center', gap:12, background:'#fff', border:'1.5px solid var(--ink,#141414)', boxShadow:'3px 3px 0 rgba(20,20,20,.12)', padding:'10px 14px', position:'relative', ...style}}>\n      <div style={{position:'absolute', left:7, top:0, bottom:0, borderLeft:'1.5px dashed var(--ink,#141414)'}}/>\n      <div style={{fontFamily:'\"Crimson Pro\",serif', fontSize:14.5, color:'var(--ink,#141414)', paddingLeft:8, flex:1}}>{children}</div>\n      {stamp}\n    </div>\n  );\n}"},{"p":"components/navigation/AppHeader.jsx","names":["AppHeader","ScreenHeader"],"src":"const { BridgeMark } = window.NickelBridge;\n/* Top chrome: glyph + Poiret wordmark, right-side tracked-caps context. */\nfunction AppHeader({context='DUPLICATE · SAYC', showMark=true, style}) {\n  return (\n    <div style={{display:'flex', alignItems:'center', justifyContent:'space-between', padding:'14px 16px', borderBottom:'1px solid var(--ink,#141414)', background:'var(--paper,#FCFBF8)', ...style}}>\n      <div style={{display:'flex', alignItems:'center', gap:9}}>\n        {showMark ? <BridgeMark width={26}/> : null}\n        <span style={{fontFamily:'\"Poiret One\",cursive', fontSize:17, letterSpacing:'.14em', color:'var(--ink,#141414)'}}>NICKEL BRIDGE</span>\n      </div>\n      <span style={{fontFamily:'Besley,serif', fontSize:8.5, letterSpacing:'.3em', color:'var(--muted,#6E6A62)'}}>{context}</span>\n    </div>\n  );\n}\n/* Sub-screen header: back chevron + Besley title, right-side caption. */\nfunction ScreenHeader({title, caption, onBack, style}) {\n  return (\n    <div style={{display:'flex', alignItems:'center', justifyContent:'space-between', padding:'12px 16px', borderBottom:'1px solid var(--ink,#141414)', background:'var(--paper,#FCFBF8)', ...style}}>\n      <div style={{display:'flex', alignItems:'baseline', gap:10}}>\n        {onBack ? <span onClick={onBack} style={{fontFamily:'Besley,serif', fontWeight:700, fontSize:14, cursor:'pointer'}}>‹</span> : null}\n        <span style={{fontFamily:'Besley,serif', fontWeight:700, fontSize:13.5, color:'var(--ink,#141414)'}}>{title}</span>\n      </div>\n      <span style={{fontFamily:'\"Crimson Pro\",serif', fontSize:12.5, color:'var(--muted,#6E6A62)'}}>{caption}</span>\n    </div>\n  );\n}"},{"p":"components/navigation/TabBar.jsx","names":["TabBar"],"src":"/* Bottom tabs — Besley caps, inset 3px ink top bar marks the active tab. */\nfunction TabBar({tabs=['CROSSINGS','STATS','RANKINGS'], active='CROSSINGS', onSelect, style}) {\n  return (\n    <div style={{display:'flex', borderTop:'1px solid var(--ink,#141414)', fontFamily:'Besley,serif', fontWeight:700, fontSize:9.5, letterSpacing:'.16em', textAlign:'center', background:'var(--paper,#FCFBF8)', ...style}}>\n      {tabs.map(t=>(\n        <div key={t} onClick={()=>onSelect && onSelect(t)} style={{flex:1, padding:'13px 0', cursor:'pointer', color:t===active?'var(--ink,#141414)':'var(--muted,#6E6A62)', boxShadow:t===active?'inset 0 3px 0 var(--ink,#141414)':'none'}}>{t}</div>\n      ))}\n    </div>\n  );\n}"},{"p":"components/game/PlayingCard.jsx","names":["PlayingCard"],"src":"const SUITS = {S:{g:'♠',c:'var(--suit-s,#141414)',dim:'#141414'},H:{g:'♥',c:'var(--suit-h,#C22F21)',dim:'#DCA9A2'},D:{g:'♦',c:'var(--suit-d,#9E6A00)',dim:'#CFBC93'},C:{g:'♣',c:'var(--suit-c,#00775A)',dim:'#9CC2B6'}};\n/* Corner-indexed playing card. Fan by overlapping with negative margins. */\nfunction PlayingCard({rank='A', suit='S', size=66, dimmed=false, selected=false, placeholder=false, style}) {\n  const w = Math.round(size*46/66);\n  const s = SUITS[suit]||SUITS.S;\n  if (placeholder) return <div style={{width:w, height:size, border:'1.5px dashed var(--line-dashed,#B9B4A9)', borderRadius:3, boxSizing:'border-box', ...style}}/>;\n  const color = dimmed ? (suit==='S'?'#141414':s.dim) : s.c;\n  return (\n    <div style={{width:w, height:size, background:'#fff', border:selected?'2px solid var(--ink,#141414)':'1px solid var(--line-dashed,#B9B4A9)', borderRadius:4, boxShadow:selected?'0 3px 6px rgba(0,0,0,.2)':'0 1px 2px rgba(0,0,0,.14)', padding:'3px 0 0 5px', fontFamily:'Besley,serif', fontWeight:800, color, boxSizing:'border-box', transform:selected?'translateY(-12px)':'none', flex:'none', ...style}}>\n      <div style={{fontSize:Math.round(size*15/66), lineHeight:1, letterSpacing:rank==='10'?'-.09em':0}}>{rank}</div>\n      <div style={{fontSize:Math.round(size*14/66)}}>{s.g}</div>\n    </div>\n  );\n}"},{"p":"components/game/StarGrade.jsx","names":["StarGrade"],"src":"/* 3-star call grade — filled ink stars + line-color remainders. */\nfunction StarGrade({stars=3, size=12, style}) {\n  return <span style={{letterSpacing:2, fontSize:size, color:'var(--ink,#141414)', ...style}}>\n    {'★★★'.slice(0,stars)}<span style={{color:'var(--line,#D8D5CE)'}}>{'★★★'.slice(stars)}</span>\n  </span>;\n}"},{"p":"ui_kits/app/screens1.jsx","names":["HomeScreen","RankingsScreen","StatsScreen"],"src":"const { AppHeader, ScreenHeader } = window.NickelBridge;\nconst { TabBar } = window.NickelBridge;\nconst { Button } = window.NickelBridge;\nconst { Chip } = window.NickelBridge;\nconst { TicketStub } = window.NickelBridge;\nconst { FlipDigits } = window.NickelBridge;\nconst { InkStamp } = window.NickelBridge;\nconst { Postmark } = window.NickelBridge;\nconst { PerforatedPanel } = window.NickelBridge;\nconst { BridgeMark } = window.NickelBridge;\nconst { PlayingCard } = window.NickelBridge;\nconst { StarGrade } = window.NickelBridge;\nconst LBL = {fontFamily:'Besley,serif', fontWeight:700, fontSize:10, letterSpacing:'.2em', color:'var(--muted)'};\nconst SCREEN = {width:390, background:'var(--paper)', fontFamily:'\"Crimson Pro\",serif', color:'var(--ink)', display:'flex', flexDirection:'column', minHeight:620, position:'relative'};\nconst NUM = {fontVariantNumeric:'tabular-nums'};\n\nfunction HomeScreen({go}) {\n  const gateRow = (n, main, sub, stamp, dashed) => (\n    <div style={{border:dashed?'1px dashed var(--line-dashed)':'1.5px solid var(--ink)', background:dashed?'transparent':'#fff', display:'flex', alignItems:'stretch', color:dashed?'var(--muted)':'var(--ink)', boxShadow:dashed?'none':'var(--ticket-shadow)'}}>\n      <div style={{width:74, borderRight:'2px dashed '+(dashed?'var(--line-dashed)':'var(--ink)'), display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', padding:'10px 0'}}>\n        <span style={{fontFamily:'Besley,serif', fontWeight:700, fontSize:9, letterSpacing:'.18em', color:'var(--muted)'}}>TOURNEY</span>\n        <span style={{fontFamily:'Besley,serif', fontWeight:800, fontSize:22}}>{n}</span>\n      </div>\n      <div style={{flex:1, padding:'10px 12px', display:'flex', alignItems:'center', gap:10}}>\n        {sub ? <div style={{flex:1}}><div style={{fontWeight:600, fontSize:15}}>{main}</div><div style={{fontSize:12.5, color:'var(--muted)'}}>{sub}</div></div>\n             : <div style={{fontSize:14, fontStyle:'italic'}}>{main}</div>}\n        {stamp}\n      </div>\n    </div>\n  );\n  return (\n    <div style={SCREEN} data-screen-label=\"Home\">\n      <AppHeader/>\n      <div style={{padding:'20px 16px 0'}}>\n        <div style={{fontWeight:600, fontSize:21}}>Good evening, Margaret</div>\n        <div style={{fontSize:14.5, color:'var(--muted)', marginTop:2}}>The bridge is open.</div>\n      </div>\n      <div style={{margin:'16px 16px 0', background:'var(--surface)', border:'1px solid var(--surface-line)', padding:'16px 14px', display:'flex', flexDirection:'column', gap:12}}>\n        <div style={{display:'flex', alignItems:'center', gap:12}}>\n          <TicketStub label=\"OPEN NOW\" value=\"4 boards\" width={132}/>\n          <div style={{flex:1, fontSize:14.5, lineHeight:1.45}}>Tournament #12<br/><span style={{color:'var(--muted)', fontSize:13}}>Board 2 of 4 in progress — your call</span></div>\n        </div>\n        <Button onClick={()=>go && go('sheet')}>KEEP GOING →</Button>\n      </div>\n      <div style={{padding:'14px 16px 0', display:'flex', flexDirection:'column', gap:10}}>\n        {gateRow('13','Opens when you finish #12 — one crossing at a time',null,null,true)}\n      </div>\n      <div style={{padding:'20px 16px 0'}}>\n        <div style={LBL}>TOLLS PAID</div>\n        <PerforatedPanel padding=\"2px 14px 2px 20px\" style={{marginTop:10}}>\n          <div style={{display:'grid', gridTemplateColumns:'auto 1fr auto auto', gap:'0 12px', fontSize:14.5, ...NUM, alignItems:'center'}}>\n            {[['11','Jul 9 · 14 pairs','54%','6TH','var(--muted)'],['10','Jul 6 · 11 pairs','63%','1ST','var(--positive)'],['9','Jul 2 · 16 pairs','47%','9TH','var(--muted)'],['8','Jun 28 · 12 pairs','59%','3RD','var(--positive)']].map(([n,d,p,r,c],i,arr)=>{\n              const bb = i<arr.length-1 ? '1px solid var(--line-quiet)' : 'none';\n              return [\n                <b key={n+'a'} style={{fontFamily:'Besley,serif', fontSize:12, padding:'10px 0'}}>{n}</b>,\n                <div key={n+'b'} style={{padding:'10px 0', borderBottom:bb}}>{d}</div>,\n                <b key={n+'c'} style={{padding:'10px 0', borderBottom:bb}}>{p}</b>,\n                <span key={n+'d'} style={{fontFamily:'Besley,serif', fontWeight:700, fontSize:11, color:c, padding:'10px 0', borderBottom:bb}}>{r}</span>\n              ];\n            })}\n          </div>\n        </PerforatedPanel>\n        <div style={{fontSize:12.5, color:'var(--muted)', marginTop:10, fontStyle:'italic', textAlign:'center'}}>Every crossing since June — tap a row for its postmark.</div>\n      </div>\n      <div style={{marginTop:'auto'}}><TabBar active=\"CROSSINGS\" onSelect={t=>go && go(t)}/></div>\n    </div>\n  );\n}\n\nfunction RankingsScreen({go}) {\n  const rows = [['1','Alice Whitmore','1642','▲2','var(--positive)'],['2','Henry Chu','1601','▼1','var(--negative)'],['3','Dot Pemberton','1583','▼1','var(--negative)'],['4','Sam Okafor','1540','—','var(--muted)'],['5','Margaret — you','1487','▲3','var(--positive)',1],['6','Ruth Adler','1466','▼2','var(--negative)'],['7','Leo Marsh','1421','—','var(--muted)']];\n  return (\n    <div style={SCREEN} data-screen-label=\"Rankings\">\n      <AppHeader context=\"RANKINGS\"/>\n      <div style={{padding:'18px 16px 0', display:'flex', alignItems:'baseline', justifyContent:'space-between'}}>\n        <div style={{fontWeight:600, fontSize:19}}>The field</div>\n        <div style={{...LBL, letterSpacing:'.16em'}}>ALL-TIME · 54 PLAYERS</div>\n      </div>\n      <PerforatedPanel padding=\"6px 14px 6px 20px\" style={{margin:'12px 16px 0'}}>\n        <div style={{display:'grid', gridTemplateColumns:'auto 1fr auto auto', gap:'0 12px', fontSize:14.5, ...NUM, alignItems:'center'}}>\n          {rows.map(([n,name,elo,d,c,you],i)=>{\n            const bb = i<rows.length-1 ? '1px solid var(--line-quiet)' : 'none';\n            const hl = you ? {background:'var(--surface)'} : {};\n            return [\n              <b key={n+'a'} style={{fontFamily:'Besley,serif', fontSize:12, padding:'9px 0', ...hl, ...(you?{marginLeft:-6, paddingLeft:6}:{})}}>{n}</b>,\n              <div key={n+'b'} style={{padding:'9px 0', borderBottom:you?'none':bb, fontWeight:you?600:400, ...hl, ...(you?{margin:'0 -12px', paddingLeft:12, paddingRight:12}:{})}}>{name}</div>,\n              <b key={n+'c'} style={{padding:'9px 0', borderBottom:you?'none':bb, ...hl, ...(you?{margin:'0 -4px', paddingLeft:4, paddingRight:4}:{})}}>{elo}</b>,\n              <span key={n+'d'} style={{fontFamily:'Besley,serif', fontWeight:700, fontSize:11, color:c, padding:'9px 0', borderBottom:you?'none':bb, ...hl, ...(you?{marginRight:-6, paddingRight:6}:{})}}>{d}</span>\n            ];\n          })}\n        </div>\n      </PerforatedPanel>\n      <div style={{margin:'12px 16px 0', background:'var(--surface)', border:'1px solid var(--surface-line)', padding:'12px 14px', display:'flex', alignItems:'center', gap:12}}>\n        <BridgeMark width={34}/>\n        <div style={{fontSize:13.5, lineHeight:1.45}}>Rankings update after every game played on the site. <span style={{color:'var(--muted)'}}>54 players crossed this week.</span></div>\n      </div>\n      <div style={{marginTop:'auto'}}><TabBar active=\"RANKINGS\" onSelect={t=>go && go(t)}/></div>\n    </div>\n  );\n}\n\nfunction StatsScreen({go}) {\n  const bar = (pct) => (\n    <div style={{height:8, background:'var(--chart-track)', position:'relative'}}><div style={{position:'absolute', inset:0, right:(100-pct)+'%', background:'var(--ink)'}}/></div>\n  );\n  return (\n    <div style={SCREEN} data-screen-label=\"Stats\">\n      <AppHeader context=\"STATS\"/>\n      <div style={{display:'flex', flexDirection:'column', alignItems:'center', padding:'20px 16px 0'}}>\n        <FlipDigits value=\"1487\" suffix=\"\" size={46}/>\n        <div style={{display:'flex', alignItems:'baseline', gap:8, marginTop:8}}>\n          <span style={{...LBL, letterSpacing:'.18em'}}>NICKEL RATING</span>\n          <span style={{fontFamily:'Besley,serif', fontWeight:700, fontSize:12, color:'var(--positive)'}}>+34 THIS MONTH</span>\n        </div>\n      </div>\n      <div style={{margin:'16px 16px 0', border:'1px solid var(--ink)', background:'#fff', padding:14}}>\n        <div style={{display:'flex', justifyContent:'space-between', alignItems:'baseline', marginBottom:10}}>\n          <span style={{...LBL, letterSpacing:'.16em'}}>MATCHPOINTS — LAST 10 TOURNAMENTS</span>\n          <span style={{fontFamily:'Besley,serif', fontWeight:800, fontSize:14, ...NUM}}>Ø 57%</span>\n        </div>\n        <svg width=\"100%\" height=\"86\" viewBox=\"0 0 326 86\" preserveAspectRatio=\"none\">\n          <line x1=\"0\" y1=\"14\" x2=\"326\" y2=\"14\" stroke=\"var(--line)\" strokeWidth=\"1\" strokeDasharray=\"3 4\"/>\n          <line x1=\"0\" y1=\"44\" x2=\"326\" y2=\"44\" stroke=\"var(--accent)\" strokeWidth=\"1.5\" strokeDasharray=\"5 4\"/>\n          <line x1=\"0\" y1=\"76\" x2=\"326\" y2=\"76\" stroke=\"var(--line)\" strokeWidth=\"1\"/>\n          <polyline points=\"6,66 41,54 76,60 111,38 146,46 181,30 216,42 251,24 286,34 320,22\" fill=\"none\" stroke=\"var(--ink)\" strokeWidth=\"2.5\"/>\n          <circle cx=\"320\" cy=\"22\" r=\"3.5\" fill=\"var(--ink)\"/>\n        </svg>\n        <div style={{display:'flex', justifyContent:'space-between', fontFamily:'Besley,serif', fontSize:9.5, color:'var(--muted)', marginTop:4}}>\n          <span>10 tournaments ago</span><span style={{color:'var(--accent)'}}>- - field average 50%</span><span>latest</span>\n        </div>\n      </div>\n      <PerforatedPanel heading=\"BIDDING — 214 CALLS GRADED\" style={{margin:'12px 16px 0'}}>\n        <div style={{display:'grid', gridTemplateColumns:'auto 1fr auto', gap:'7px 12px', fontSize:13.5, alignItems:'center', ...NUM}}>\n          <StarGrade stars={3}/>{bar(64)}<b>64%</b>\n          <StarGrade stars={2}/>{bar(27)}<b>27%</b>\n          <StarGrade stars={1}/>{bar(9)}<b>9%</b>\n        </div>\n        <div style={{fontSize:12.5, color:'var(--muted)', marginTop:10, fontStyle:'italic'}}>Most-missed call: invitational raises after 1NT rebids.</div>\n      </PerforatedPanel>\n      <div style={{margin:'12px 16px 0', display:'flex', gap:10}}>\n        {[['DECLARING','61%','88 boards'],['DEFENDING','52%','126 boards']].map(([l,v,s])=>(\n          <div key={l} style={{flex:1, border:'1px solid var(--ink)', background:'#fff', padding:'12px 14px'}}>\n            <div style={{...LBL, fontSize:9.5, letterSpacing:'.16em'}}>{l}</div>\n            <div style={{fontFamily:'Besley,serif', fontWeight:800, fontSize:21, ...NUM, marginTop:4}}>{v}</div>\n            <div style={{fontSize:12, color:'var(--muted)'}}>{s}</div>\n          </div>\n        ))}\n      </div>\n      <div style={{marginTop:'auto'}}><TabBar active=\"STATS\" onSelect={t=>go && go(t)}/></div>\n    </div>\n  );\n}\n"},{"p":"ui_kits/app/screens2.jsx","names":["TournamentSheetScreen","CallInspectorScreen","TournamentResultScreen","SplashIntro"],"src":"const { ScreenHeader } = window.NickelBridge;\nconst { Button } = window.NickelBridge;\nconst { Chip } = window.NickelBridge;\nconst { Dialog } = window.NickelBridge;\nconst { TicketStub } = window.NickelBridge;\nconst { FlipDigits } = window.NickelBridge;\nconst { InkStamp } = window.NickelBridge;\nconst { Postmark } = window.NickelBridge;\nconst { PerforatedPanel } = window.NickelBridge;\nconst LBL = {fontFamily:'Besley,serif', fontWeight:700, fontSize:10, letterSpacing:'.2em', color:'var(--muted)'};\nconst SCREEN = {width:390, background:'var(--paper)', fontFamily:'\"Crimson Pro\",serif', color:'var(--ink)', display:'flex', flexDirection:'column', minHeight:620, position:'relative'};\nconst NUM = {fontVariantNumeric:'tabular-nums'};\n\nfunction BoardRow({n, main, sub, stamp, state}) {\n  const sealed = state==='sealed', live = state==='live';\n  const border = sealed ? '1px dashed var(--line-dashed)' : (live ? '1.5px solid var(--ink)' : '1px solid var(--ink)');\n  return (\n    <div style={{border, background:sealed?'transparent':'#fff', display:'flex', alignItems:'stretch', color:sealed?'var(--muted)':'var(--ink)', boxShadow:live?'var(--ticket-shadow)':'none'}}>\n      <div style={{width:74, borderRight:'2px dashed '+(sealed?'var(--line-dashed)':'var(--ink)'), display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', padding:'10px 0'}}>\n        <span style={{fontFamily:'Besley,serif', fontWeight:700, fontSize:9, letterSpacing:'.18em', color:'var(--muted)'}}>BOARD</span>\n        <span style={{fontFamily:'Besley,serif', fontWeight:800, fontSize:22}}>{n}</span>\n      </div>\n      <div style={{flex:1, padding:'10px 12px', display:'flex', alignItems:'center', gap:10}}>\n        {sub ? <div style={{flex:1}}><div style={{fontWeight:600, fontSize:15}}>{main}</div><div style={{fontSize:12.5, color:'var(--muted)', ...NUM}}>{sub}</div></div>\n             : <div style={{fontSize:14, fontStyle:'italic'}}>{main}</div>}\n        {stamp}\n      </div>\n    </div>\n  );\n}\n\nfunction TournamentSheetScreen({go}) {\n  return (\n    <div style={SCREEN} data-screen-label=\"Tournament sheet\">\n      <ScreenHeader title=\"Tournament #12\" caption=\"12 pairs · matchpoints\" onBack={()=>go && go('HOME')}/>\n      <div style={{padding:'14px 16px 0', display:'flex', flexDirection:'column', gap:10}}>\n        <BoardRow n=\"1\" main=\"4♠= by S · +620\" sub=\"58% matchpoints\" state=\"scored\" stamp={<InkStamp size={10} rotate={-5}>SCORED</InkStamp>}/>\n        <BoardRow n=\"2\" main=\"Bidding — your call\" sub=\"Dealer N · NS vul\" state=\"live\" stamp={<InkStamp color=\"var(--suit-h)\" rotate={3} fade=\"left\" size={10}>LIVE</InkStamp>}/>\n        <BoardRow n=\"3\" main=\"Sealed — deals when board 2 is scored\" state=\"sealed\"/>\n        <BoardRow n=\"4\" main=\"Sealed\" state=\"sealed\"/>\n      </div>\n      <PerforatedPanel heading=\"THE FIELD — AFTER BOARD 1\" style={{margin:'14px 16px 0'}}>\n        <div style={{display:'grid', gridTemplateColumns:'auto 1fr auto', gap:'6px 12px', fontSize:14, ...NUM, alignItems:'baseline'}}>\n          <b style={{fontFamily:'Besley,serif', fontSize:12}}>1</b><div>Alice</div><b>83%</b>\n          <b style={{fontFamily:'Besley,serif', fontSize:12, background:'var(--surface)', margin:'0 -4px', padding:'0 4px'}}>2</b>\n          <div style={{fontWeight:600, background:'var(--surface)', margin:'0 -12px', padding:'0 12px'}}>You</div>\n          <b style={{background:'var(--surface)', margin:'0 -4px', padding:'0 4px'}}>58%</b>\n          <b style={{fontFamily:'Besley,serif', fontSize:12}}>3</b><div>Bob</div><b>33%</b>\n        </div>\n      </PerforatedPanel>\n      <div style={{padding:'14px 16px 18px', marginTop:'auto'}}><Button onClick={()=>go && go('board')}>CONTINUE BOARD 2 →</Button></div>\n    </div>\n  );\n}\n\nfunction CallInspectorScreen({go}) {\n  return (\n    <div style={{...SCREEN, height:620, overflow:'hidden'}} data-screen-label=\"Call inspector\">\n      <div style={{padding:12, filter:'grayscale(.2)'}}>\n        <div style={{border:'1px solid var(--ink)', padding:2}}><div style={{border:'1px solid var(--ink)', padding:'10px 12px 12px', fontFamily:'Besley,serif'}}>\n          <div style={{display:'grid', gridTemplateColumns:'repeat(4,1fr)', textAlign:'center', fontSize:10.5, fontWeight:700, letterSpacing:'.14em', color:'var(--muted)', paddingBottom:6, borderBottom:'1px solid var(--line)'}}>\n            <div>N</div><div>E</div><div style={{color:'var(--ink)'}}>S ★</div><div>W</div>\n          </div>\n          <div style={{display:'grid', gridTemplateColumns:'repeat(4,1fr)', textAlign:'center', fontSize:15, fontWeight:600, rowGap:7, paddingTop:8, ...NUM}}>\n            <div style={{color:'var(--muted)'}}>—</div><div style={{color:'var(--muted)'}}>—</div>\n            <div style={{borderBottom:'2px dotted var(--ink)', justifySelf:'center', padding:'0 5px'}}>1<span style={{color:'var(--suit-h)'}}>♥</span></div><div>Pass</div>\n            <div style={{outline:'2px solid var(--ink)', outlineOffset:3, justifySelf:'center', padding:'0 5px', fontWeight:800}}>1NT</div><div>Pass</div>\n            <div style={{color:'var(--muted)'}}>?</div><div></div>\n          </div>\n        </div></div>\n      </div>\n      <Dialog title=\"1NT — partner's response\" onClose={()=>go && go('sheet')}>\n        <div style={{display:'flex', gap:6, margin:'10px 0 12px', flexWrap:'wrap'}}>\n          <Chip>6–9 HCP</Chip><Chip>NO 4-CARD MAJOR TO BID</Chip><Chip quiet>DENIES 3 HEARTS</Chip>\n        </div>\n        <div style={{fontSize:15, lineHeight:1.5}}>A catch-all response: partner has enough to keep the auction open but cannot raise hearts or bid a suit at the one level. Not a balanced-hand promise — this is SAYC's \"I have something, but nothing to say.\"</div>\n        <PerforatedPanel heading=\"WHAT YOU KNOW ABOUT PARTNER\" style={{marginTop:14, background:'var(--paper)'}} padding=\"10px 12px 10px 18px\">\n          <div style={{fontSize:13.5, lineHeight:1.7}}>6–9 points, fewer than three hearts<br/>No four spades — would have bid 1♠<br/>Minors still unknown</div>\n        </PerforatedPanel>\n        <div style={{fontSize:12.5, color:'var(--muted)', marginTop:12, fontStyle:'italic'}}>With 3+ hearts and 6–9, partner raises to 2<span style={{color:'var(--suit-h)'}}>♥</span> instead.</div>\n      </Dialog>\n    </div>\n  );\n}\n\nfunction TournamentResultScreen({go}) {\n  const bar = (pct) => <div style={{width:52, height:6, background:'var(--chart-track)', position:'relative'}}><div style={{position:'absolute', inset:0, right:(100-pct)+'%', background:'var(--ink)'}}/></div>;\n  return (\n    <div style={SCREEN} data-screen-label=\"Tournament result\">\n      <ScreenHeader title=\"Tournament #12\" caption=\"Complete · 12 pairs\"/>\n      <div style={{display:'flex', flexDirection:'column', alignItems:'center', padding:'22px 16px 0'}}>\n        <Postmark size={118} arcBottom=\"TOURNAMENT Nº12\" line1=\"TOLL PAID\" line2=\"JUL 13 1926\"/>\n        <div style={{marginTop:16}}><FlipDigits value=\"61\" suffix=\"%\" size={54}/></div>\n        <div style={{fontFamily:'Besley,serif', fontSize:11, fontWeight:700, letterSpacing:'.16em', color:'var(--muted)', marginTop:8}}>MATCHPOINTS · 2ND OF 12 PAIRS</div>\n        <div style={{display:'flex', alignItems:'baseline', gap:8, marginTop:10}}>\n          <span style={{...LBL, letterSpacing:'.18em'}}>NICKEL RATING</span>\n          <span style={{fontFamily:'Besley,serif', fontWeight:800, fontSize:16, ...NUM}}>1487</span>\n          <span style={{fontFamily:'Besley,serif', fontWeight:700, fontSize:13, color:'var(--positive)'}}>+12</span>\n        </div>\n      </div>\n      <PerforatedPanel heading=\"BOARD BY BOARD\" style={{margin:'16px 16px 0'}}>\n        <div style={{display:'grid', gridTemplateColumns:'auto 1fr auto auto', gap:'7px 12px', fontSize:13.5, ...NUM, alignItems:'center'}}>\n          {[['1','4♠= by S','+620',58],['2','3NT+1 by N','+630',74],['3','2♥−1 by S','−100',41],['4','4♥= by W','−420',71]].map(([n,c,s,p])=>[\n            <b key={n+'a'} style={{fontFamily:'Besley,serif', fontSize:12}}>{n}</b>,\n            <div key={n+'b'}>{c}</div>,\n            <div key={n+'c'} style={{color:'var(--muted)'}}>{s}</div>,\n            <div key={n+'d'} style={{display:'flex', alignItems:'center', gap:6}}>{bar(p)}<b>{p}</b></div>\n          ])}\n        </div>\n      </PerforatedPanel>\n      <div style={{padding:'16px 16px 18px', display:'flex', flexDirection:'column', gap:8, marginTop:'auto'}}>\n        <Button onClick={()=>go && go('HOME')}>BACK TO THE BRIDGE →</Button>\n        <Button variant=\"secondary\">Review the boards</Button>\n      </div>\n    </div>\n  );\n}\n\n/* Intro: splash (6c) pays the toll, crosses into Home — approved 7a sequence, coin removed. */\nfunction SplashIntro({onDone, riverSrc='../../assets/bridge-river-scene.svg', children}) {\n  const [k, setK] = React.useState(0);\n  React.useEffect(()=>{ const t = setTimeout(()=>onDone && onDone(), 3300); return ()=>clearTimeout(t); }, [k]);\n  return (\n    <div style={{width:390, height:620, background:'var(--paper)', position:'relative', overflow:'hidden'}} data-screen-label=\"Splash intro\">\n      <style>{'@keyframes nbWordIn{from{opacity:0;letter-spacing:.34em}to{opacity:1;letter-spacing:.16em}}@keyframes nbSubIn{from{opacity:0}to{opacity:1}}@keyframes nbBridgeRise{from{transform:translateY(150px)}to{transform:translateY(0)}}@keyframes nbSplashOut{to{opacity:0;transform:translateY(-26px)}}@keyframes nbBridgeOut{to{transform:translateY(170px)}}@keyframes nbHomeIn{from{opacity:0;transform:translateY(14px)}to{opacity:1;transform:translateY(0)}}'}</style>\n      <div key={'s'+k} style={{position:'absolute', inset:0, display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', gap:24, paddingBottom:130, animation:'nbSplashOut .55s ease-in 2.1s forwards'}}>\n        <div style={{textAlign:'center'}}>\n          <div style={{fontFamily:'\"Poiret One\",cursive', fontSize:32, letterSpacing:'.16em', color:'var(--ink)', animation:'nbWordIn .9s ease-out both'}}>NICKEL BRIDGE</div>\n          <div style={{fontFamily:'Besley,serif', fontSize:10.5, letterSpacing:'.42em', color:'var(--ink)', marginTop:6, animation:'nbSubIn .6s ease-out .5s both'}}>DUPLICATE · SAYC</div>\n        </div>\n        <div style={{width:280, background:'var(--ink)', color:'#fff', textAlign:'center', fontFamily:'Besley,serif', fontWeight:800, fontSize:15, letterSpacing:'.06em', padding:13, borderRadius:2, animation:'nbSubIn .6s ease-out .8s both'}}>PLAY THE TOLL →</div>\n      </div>\n      <div key={'b'+k} style={{position:'absolute', bottom:0, left:0, width:390, height:146, animation:'nbBridgeRise .9s cubic-bezier(.2,.7,.2,1) both, nbBridgeOut .6s ease-in 2.1s forwards'}}>\n        <img src={riverSrc} width=\"390\" height=\"146\" style={{display:'block', objectFit:'cover', objectPosition:'bottom'}} alt=\"\"/>\n      </div>\n      <div key={'h'+k} style={{position:'absolute', inset:0, animation:'nbHomeIn .7s cubic-bezier(.2,.7,.2,1) 2.45s both'}}>\n        {children}\n      </div>\n      <div onClick={()=>setK(k+1)} style={{position:'absolute', right:8, top:8, zIndex:20, cursor:'pointer', border:'1px solid var(--line)', borderRadius:4, padding:'4px 10px', font:'600 11px system-ui,sans-serif', color:'var(--muted)', background:'rgba(255,255,255,.85)'}}>↻</div>\n    </div>\n  );\n}\n"},{"p":"ui_kits/app/screens3.jsx","names":["BoardBiddingScreen","BoardPlayScreen","BoardResultScreen"],"src":"const { Button } = window.NickelBridge;\nconst { Chip } = window.NickelBridge;\nconst { InkStamp } = window.NickelBridge;\nconst { FlipDigits } = window.NickelBridge;\nconst { PerforatedPanel } = window.NickelBridge;\nconst { PlayingCard } = window.NickelBridge;\nconst { StarGrade } = window.NickelBridge;\nconst NUM = {fontVariantNumeric:'tabular-nums'};\nconst SCREEN = {width:390, background:'var(--paper)', fontFamily:'Besley,serif', color:'var(--ink)', display:'flex', flexDirection:'column', position:'relative'};\nconst SUIT = {S:'var(--suit-s)',H:'var(--suit-h)',D:'var(--suit-d)',C:'var(--suit-c)'};\nconst Sym = ({s,dim}) => s==='NT'||!s ? null : <span style={{color:dim||SUIT[s]}}>{{S:'♠',H:'♥',D:'♦',C:'♣'}[s]}</span>;\nfunction Fan({cards, size=66}) {\n  return (\n    <div style={{display:'flex', justifyContent:'center', alignItems:'flex-end', padding:'0 8px'}}>\n      {cards.map((c,i)=>{\n        const prev = cards[i-1];\n        const ml = i===0 ? 0 : (prev && prev.suit!==c.suit ? -Math.round(size*20/66) : -Math.round(size*26/66));\n        return <PlayingCard key={i} rank={c.r} suit={c.suit} size={size} dimmed={c.dim} selected={c.sel} style={{marginLeft:ml}}/>;\n      })}\n    </div>\n  );\n}\nfunction HCP({n, style}) { return <span style={{background:'var(--ink)', color:'#fff', fontWeight:800, fontSize:12, padding:'2px 9px', borderRadius:3, ...NUM, ...style}}>{n} HCP</span>; }\nfunction SeatLabel({children, style}) { return <span style={{fontSize:11, fontWeight:700, letterSpacing:'.14em', color:'var(--muted)', ...style}}>{children}</span>; }\n\nfunction BoardBiddingScreen({go}) {\n  const hand = [{r:'A',suit:'S'},{r:'Q',suit:'S'},{r:'10',suit:'S'},{r:'K',suit:'H'},{r:'J',suit:'H'},{r:'9',suit:'H'},{r:'6',suit:'H'},{r:'3',suit:'H'},{r:'8',suit:'D'},{r:'2',suit:'D'},{r:'Q',suit:'C'},{r:'9',suit:'C'},{r:'5',suit:'C'}];\n  const bids = [];\n  for (let lvl=1; lvl<=4; lvl++) for (const s of ['C','D','H','S','NT']) bids.push({lvl, s});\n  const isDisabled = (b) => b.lvl<2 || (b.lvl===2 && ['C','D'].includes(b.s));\n  const isSel = (b) => b.lvl===2 && b.s==='H';\n  return (\n    <div style={SCREEN} data-screen-label=\"Board — bidding\">\n      <div style={{display:'flex', alignItems:'center', justifyContent:'space-between', padding:'12px 16px 10px', borderBottom:'1px solid var(--ink)'}}>\n        <div style={{fontFamily:'\"Poiret One\",cursive', fontSize:15, letterSpacing:'.14em'}}>NICKEL BRIDGE</div>\n        <div style={{display:'flex', gap:14, fontSize:12, fontWeight:600}}><span>Stats</span><span>Rankings</span></div>\n      </div>\n      <div style={{display:'flex', alignItems:'center', gap:10, padding:'10px 16px', borderBottom:'1px solid var(--line)'}}>\n        <svg width=\"92\" height=\"34\" viewBox=\"0 0 92 34\"><rect x=\"1.5\" y=\"1.5\" width=\"89\" height=\"31\" fill=\"#fff\" stroke=\"var(--ink)\" strokeWidth=\"2.5\"/><line x1=\"64\" y1=\"1\" x2=\"64\" y2=\"33\" stroke=\"var(--ink)\" strokeWidth=\"1.5\" strokeDasharray=\"2.5 4\"/><text x=\"8\" y=\"13\" fontFamily=\"Besley,serif\" fontWeight=\"700\" fontSize=\"7.5\" letterSpacing=\"1.5\" fill=\"var(--ink)\">BOARD</text><text x=\"8\" y=\"27\" fontFamily=\"Besley,serif\" fontWeight=\"800\" fontSize=\"13\" fill=\"var(--ink)\">2 of 4</text><text x=\"82\" y=\"8\" fontFamily=\"Besley,serif\" fontWeight=\"700\" fontSize=\"6\" letterSpacing=\"1\" fill=\"var(--ink)\" transform=\"rotate(90 82 8)\">ADMIT</text></svg>\n        <div style={{flex:1, minWidth:0}}><div style={{fontWeight:700, fontSize:13.5, whiteSpace:'nowrap', overflow:'hidden', textOverflow:'ellipsis'}}>Tournament #12</div><div style={{fontSize:12, color:'var(--muted)'}}>Dealer N</div></div>\n        <Chip color=\"var(--suit-h)\" style={{fontWeight:800, fontSize:10.5, letterSpacing:'.12em', border:'1.5px solid var(--suit-h)'}}>NS VUL</Chip>\n      </div>\n      <div style={{margin:'12px 12px 0', border:'1px solid var(--ink)', padding:2}}><div style={{border:'1px solid var(--ink)', padding:'10px 12px 12px'}}>\n        <div style={{display:'grid', gridTemplateColumns:'repeat(4,1fr)', textAlign:'center', fontSize:10.5, fontWeight:700, letterSpacing:'.14em', color:'var(--muted)', paddingBottom:6, borderBottom:'1px solid var(--line)'}}>\n          <div>N</div><div>E</div><div style={{color:'var(--ink)'}}>S ★</div><div>W</div>\n        </div>\n        <div style={{display:'grid', gridTemplateColumns:'repeat(4,1fr)', textAlign:'center', fontSize:15, fontWeight:600, rowGap:7, paddingTop:8, ...NUM}}>\n          <div style={{color:'var(--muted)'}}>—</div><div style={{color:'var(--muted)'}}>—</div>\n          <div style={{borderBottom:'2px dotted var(--ink)', justifySelf:'center', padding:'0 5px'}}>1<Sym s=\"H\"/></div><div>Pass</div>\n          <div style={{borderBottom:'2px dotted var(--ink)', justifySelf:'center', padding:'0 5px'}}>1NT</div><div>Pass</div>\n          <div style={{outline:'1.5px solid var(--ink)', outlineOffset:2, justifySelf:'center', padding:'0 5px', fontWeight:800}}>?</div><div></div>\n        </div>\n        <div style={{fontSize:10.5, color:'var(--muted)', textAlign:'center', marginTop:9, letterSpacing:'.06em'}}>dotted = has a SAYC meaning · tap any call to inspect</div>\n      </div></div>\n      <PerforatedPanel style={{margin:'10px 12px 0'}} padding=\"11px 14px 12px 20px\">\n        <div style={{fontWeight:800, fontSize:14.5}}>Your 2<Sym s=\"H\"/> — Rebid, invitational</div>\n        <div style={{display:'flex', gap:6, margin:'6px 0 7px'}}><Chip style={{padding:'2px 7px'}}>10–12 HCP</Chip><Chip quiet style={{padding:'2px 7px'}}>6+ hearts</Chip></div>\n        <div style={{fontSize:13.5, lineHeight:1.5, fontWeight:400}}>Shows a long heart suit worth rebidding and invitational values opposite partner's 1NT. Partner passes with a minimum.</div>\n      </PerforatedPanel>\n      <div style={{paddingTop:14}}><Fan cards={hand}/></div>\n      <div style={{display:'flex', justifyContent:'center', alignItems:'center', gap:8, marginTop:8}}>\n        <SeatLabel>SOUTH — YOU</SeatLabel><HCP n={12}/>\n      </div>\n      <div style={{padding:'12px 12px 0'}}>\n        <div style={{display:'grid', gridTemplateColumns:'repeat(5,1fr)', gap:5, ...NUM}}>\n          {bids.map((b,i)=>{\n            const sel = isSel(b), dis = isDisabled(b);\n            return (\n              <div key={i} style={{border:sel?'none':'1px solid '+(dis?'var(--line)':'var(--ink)'), background:sel?'var(--ink)':'#fff', color:sel?'#fff':'var(--ink)', minHeight:44, display:'flex', alignItems:'center', justifyContent:'center', fontWeight:sel?800:700, fontSize:16, opacity:dis?.25:1, borderRadius:2}}>\n                {b.lvl}{b.s==='NT'?'NT':<Sym s={b.s} dim={sel&&b.s==='H'?'#FF9D94':undefined}/>}\n              </div>\n            );\n          })}\n        </div>\n        <div style={{textAlign:'center', fontSize:11, color:'var(--muted)', padding:'6px 0 2px', letterSpacing:'.08em'}}>▾ levels 5–7 below the fold ▾</div>\n        <div style={{display:'grid', gridTemplateColumns:'2fr 1fr 1fr', gap:5, marginTop:2}}>\n          <div style={{border:'1px solid var(--ink)', background:'#fff', minHeight:44, display:'flex', alignItems:'center', justifyContent:'center', fontWeight:700, fontSize:15, borderRadius:2}}>Pass</div>\n          <div style={{border:'1px solid var(--ink)', background:'#fff', minHeight:44, display:'flex', alignItems:'center', justifyContent:'center', fontWeight:700, fontSize:15, borderRadius:2, color:'var(--suit-h)'}}>X</div>\n          <div style={{border:'1px solid var(--line)', background:'#fff', minHeight:44, display:'flex', alignItems:'center', justifyContent:'center', fontWeight:700, fontSize:15, opacity:.25, borderRadius:2}}>XX</div>\n        </div>\n      </div>\n      <div style={{padding:'12px 12px 16px'}}><Button onClick={()=>go && go('play')} style={{fontSize:17, padding:14}}>BID 2♥ →</Button></div>\n    </div>\n  );\n}\n\nfunction BoardPlayScreen({go}) {\n  const dummy = [{r:'K',suit:'S'},{r:'J',suit:'S'},{r:'4',suit:'S'},{r:'8',suit:'H',dim:1},{r:'2',suit:'H',dim:1},{r:'A',suit:'D',dim:1},{r:'Q',suit:'D',dim:1},{r:'7',suit:'D',dim:1},{r:'K',suit:'C',dim:1},{r:'8',suit:'C',dim:1}];\n  const hand = [{r:'A',suit:'S'},{r:'Q',suit:'S',sel:1},{r:'10',suit:'S'},{r:'6',suit:'S'},{r:'K',suit:'H',dim:1},{r:'J',suit:'H',dim:1},{r:'8',suit:'D',dim:1},{r:'Q',suit:'C',dim:1},{r:'5',suit:'C',dim:1}];\n  const seat = (label, card, pos) => (\n    <div style={{position:'absolute', ...pos, display:'flex', flexDirection:'column', alignItems:'center', gap:3}}>\n      <SeatLabel style={{fontSize:10, letterSpacing:'.12em'}}>{label}</SeatLabel>\n      {card}\n    </div>\n  );\n  return (\n    <div style={SCREEN} data-screen-label=\"Board — card play\">\n      <div style={{display:'flex', alignItems:'center', justifyContent:'space-between', padding:'10px 16px', borderBottom:'1px solid var(--ink)'}}>\n        <div style={{display:'flex', alignItems:'baseline', gap:10}}><span style={{fontWeight:700, fontSize:13.5}}>Tournament #12</span><span style={{fontSize:12, color:'var(--muted)'}}>Board 2/4</span></div>\n        <div style={{display:'flex', alignItems:'center', gap:8}}><span style={{fontWeight:800, fontSize:14}}>4♠ by S</span><Chip color=\"var(--suit-h)\" style={{fontWeight:800, fontSize:10, letterSpacing:'.1em', border:'1.5px solid var(--suit-h)', padding:'2px 6px'}}>NS VUL</Chip></div>\n      </div>\n      <div style={{display:'flex', justifyContent:'center', alignItems:'center', gap:8, padding:'12px 0 2px'}}>\n        <SeatLabel>NORTH — DUMMY</SeatLabel><HCP n={10}/>\n      </div>\n      <div style={{padding:'6px 0 0'}}><Fan cards={dummy} size={58}/></div>\n      <div style={{textAlign:'center', fontSize:10.5, color:'var(--muted)', padding:'2px 0 6px', letterSpacing:'.06em'}}>spades are live — you must follow suit</div>\n      <div style={{margin:'4px 12px 0', border:'1px solid var(--ink)', background:'var(--paper)', position:'relative', height:230}}>\n        {seat('N · DUMMY', <PlayingCard rank=\"4\" suit=\"S\" size={52}/>, {top:10, left:'50%', transform:'translateX(-50%)'})}\n        {seat('E', <PlayingCard rank=\"9\" suit=\"H\" size={52}/>, {right:14, top:'50%', transform:'translateY(-50%)'})}\n        {seat('W', <PlayingCard rank=\"Q\" suit=\"H\" size={52}/>, {left:14, top:'50%', transform:'translateY(-50%)'})}\n        <div style={{position:'absolute', bottom:10, left:'50%', transform:'translateX(-50%)', display:'flex', flexDirection:'column', alignItems:'center', gap:3}}>\n          <PlayingCard placeholder size={52}/>\n          <SeatLabel style={{fontSize:10, fontWeight:800, color:'var(--ink)'}}>S · DECL — YOU</SeatLabel>\n        </div>\n        <div style={{position:'absolute', top:'50%', left:'50%', transform:'translate(-50%,-50%)', textAlign:'center'}}>\n          <div style={{display:'flex', gap:2, justifyContent:'center'}}>\n            <div style={{width:22, height:32, background:'var(--ink)', color:'#fff', fontWeight:800, fontSize:17, display:'flex', alignItems:'center', justifyContent:'center', borderRadius:2}}>3</div>\n            <div style={{width:22, height:32, background:'#fff', border:'1.5px solid var(--ink)', fontWeight:800, fontSize:15, display:'flex', alignItems:'center', justifyContent:'center', borderRadius:2, boxSizing:'border-box'}}>1</div>\n          </div>\n          <div style={{fontSize:9.5, fontWeight:700, letterSpacing:'.1em', color:'var(--muted)', marginTop:4}}>DECL · DEF<br/>TRICK 5 OF 13</div>\n        </div>\n      </div>\n      <div style={{paddingTop:12}}><Fan cards={hand}/></div>\n      <div style={{display:'flex', justifyContent:'center', alignItems:'center', gap:8, padding:'8px 0 6px'}}>\n        <SeatLabel style={{color:'var(--ink)'}}>SOUTH — YOU · YOUR TURN</SeatLabel><HCP n={12}/>\n      </div>\n      <div onClick={()=>go && go('result')} style={{textAlign:'center', fontStyle:'italic', fontSize:13, color:'var(--muted)', padding:'0 0 16px', cursor:'pointer'}}>Q♠ selected — tap again to play</div>\n    </div>\n  );\n}\n\nfunction BoardResultScreen({go}) {\n  const bar = (pct) => <div style={{width:56, height:6, background:'var(--chart-track)', position:'relative'}}><div style={{position:'absolute', inset:0, right:(100-pct)+'%', background:'var(--ink)'}}/></div>;\n  const hand = (label, cards, strong) => (\n    <div style={{border:strong?'1.5px solid var(--ink)':'1px solid var(--line)', padding:'6px 8px'}}>\n      <b style={{fontSize:10, letterSpacing:'.1em', color:strong?'var(--ink)':'var(--muted)'}}>{label}</b><br/>\n      <span>♠ {cards[0]}</span><br/><span style={{color:'var(--suit-h)'}}>♥ {cards[1]}</span><br/><span style={{color:'var(--suit-d)'}}>♦ {cards[2]}</span><br/><span style={{color:'var(--suit-c)'}}>♣ {cards[3]}</span>\n    </div>\n  );\n  return (\n    <div style={SCREEN} data-screen-label=\"Board — result\">\n      <div style={{display:'flex', alignItems:'center', justifyContent:'space-between', padding:'10px 16px', borderBottom:'1px solid var(--ink)'}}>\n        <div style={{display:'flex', alignItems:'baseline', gap:10}}><span style={{fontWeight:700, fontSize:13.5}}>Tournament #12</span><span style={{fontSize:12, color:'var(--muted)'}}>Board 2/4</span></div>\n        <div style={{border:'2px solid var(--ink)', borderRadius:5, padding:'2px 9px', transform:'rotate(-4deg)'}}><span style={{fontWeight:800, fontSize:11, letterSpacing:'.18em'}}>SCORED</span></div>\n      </div>\n      <div style={{textAlign:'center', padding:'20px 16px 6px'}}>\n        <div style={{fontWeight:800, fontSize:23}}>4♠= by S</div>\n        <div style={{fontSize:13.5, color:'var(--muted)', marginTop:2, fontWeight:400}}>+620 for N–S · NS vul</div>\n        <div style={{display:'flex', justifyContent:'center', marginTop:14}}>\n          <FlipDigits value=\"58\" suffix=\"%\" size={54}/>\n        </div>\n        <div style={{fontSize:11, fontWeight:700, letterSpacing:'.16em', color:'var(--muted)', marginTop:8}}>MATCHPOINTS · VS 3 OTHER PLAYERS · BIDDING 89%</div>\n      </div>\n      <PerforatedPanel heading=\"THE FIELD — BOARD 2\" style={{margin:'14px 12px 0'}}>\n        <div style={{display:'grid', gridTemplateColumns:'1fr auto auto', gap:'6px 14px', fontSize:13, ...NUM, alignItems:'center', fontWeight:400}}>\n          <div>Alice</div><div style={{color:'var(--muted)'}}>4♠+1 · +650</div><div style={{display:'flex', alignItems:'center', gap:6, justifyContent:'flex-end'}}>{bar(83)}<b>83</b></div>\n          <div style={{fontWeight:800, background:'var(--surface)', margin:'0 -6px', padding:'2px 6px'}}>You</div><div style={{color:'var(--muted)', background:'var(--surface)', margin:'0 -14px', padding:'2px 14px'}}>4♠= · +620</div><div style={{display:'flex', alignItems:'center', gap:6, justifyContent:'flex-end', background:'var(--surface)', margin:'0 -6px', padding:'2px 6px'}}>{bar(58)}<b>58</b></div>\n          <div>Bob</div><div style={{color:'var(--muted)'}}>3♠+1 · +170</div><div style={{display:'flex', alignItems:'center', gap:6, justifyContent:'flex-end'}}>{bar(33)}<b>33</b></div>\n          <div>Cara</div><div style={{color:'var(--muted)'}}>4♠−1 · −100</div><div style={{display:'flex', alignItems:'center', gap:6, justifyContent:'flex-end'}}>{bar(8)}<b>8</b></div>\n        </div>\n      </PerforatedPanel>\n      <div style={{margin:'12px 12px 0', border:'1px solid var(--ink)', background:'#fff', padding:14}}>\n        <div style={{display:'flex', justifyContent:'space-between', alignItems:'baseline', marginBottom:10}}>\n          <span style={{fontWeight:700, fontSize:11, letterSpacing:'.16em', color:'var(--muted)'}}>THE DEAL</span>\n          <span style={{fontSize:11, color:'var(--muted)', fontWeight:400}}>Dealer N · NS vul</span>\n        </div>\n        <div style={{display:'grid', gridTemplateColumns:'1fr 1fr 1fr', gap:4, fontSize:11.5, lineHeight:1.55, ...NUM, fontWeight:400}}>\n          <div></div>{hand('NORTH · DUMMY',['K J 4','8 2','A Q 7 4','K 8 6 3'])}<div></div>\n          {hand('WEST',['8 3','Q 10 7 5','K J 9','J 10 7 2'])}\n          <div style={{display:'flex', alignItems:'center', justifyContent:'center'}}>\n            <svg width=\"48\" height=\"48\" viewBox=\"0 0 48 48\"><line x1=\"24\" y1=\"14\" x2=\"24\" y2=\"34\" stroke=\"var(--line)\" strokeWidth=\"1.5\"/><line x1=\"14\" y1=\"24\" x2=\"34\" y2=\"24\" stroke=\"var(--line)\" strokeWidth=\"1.5\"/><text x=\"24\" y=\"10\" textAnchor=\"middle\" fontFamily=\"Besley,serif\" fontWeight=\"700\" fontSize=\"10\" fill=\"var(--ink)\">N</text><text x=\"24\" y=\"45\" textAnchor=\"middle\" fontFamily=\"Besley,serif\" fontSize=\"10\" fill=\"var(--muted)\">S</text><text x=\"7\" y=\"27.5\" textAnchor=\"middle\" fontFamily=\"Besley,serif\" fontSize=\"10\" fill=\"var(--muted)\">W</text><text x=\"41\" y=\"27.5\" textAnchor=\"middle\" fontFamily=\"Besley,serif\" fontSize=\"10\" fill=\"var(--muted)\">E</text></svg>\n          </div>\n          {hand('EAST',['9 7 5 2','A 9 4','10 6 5 3','A 4'])}\n          <div></div>{hand('SOUTH · YOU',['A Q 10 6','K J 6 3','8 2','Q 9 5'], true)}<div></div>\n        </div>\n      </div>\n      <div style={{margin:'12px 12px 0', border:'1px solid var(--ink)', background:'#fff', padding:14}}>\n        <div style={{fontWeight:700, fontSize:11, letterSpacing:'.16em', color:'var(--muted)', marginBottom:8}}>YOUR BIDDING</div>\n        <div style={{display:'flex', flexDirection:'column', gap:7, fontSize:13, fontWeight:400}}>\n          <div style={{display:'flex', alignItems:'baseline', gap:10}}><b style={{minWidth:38}}>1<Sym s=\"H\"/></b><StarGrade stars={3}/><span>Excellent</span></div>\n          <div style={{display:'flex', alignItems:'baseline', gap:10}}><b style={{minWidth:38}}>2<Sym s=\"H\"/></b><StarGrade stars={2}/><span>Good — AI preferred 3<Sym s=\"H\"/></span></div>\n          <div style={{display:'flex', alignItems:'baseline', gap:10}}><b style={{minWidth:38}}>4♠</b><StarGrade stars={3}/><span>Excellent — the AI's choice too</span></div>\n        </div>\n      </div>\n      <div style={{padding:'14px 12px 18px', display:'flex', flexDirection:'column', gap:8}}>\n        <Button onClick={()=>go && go('sheet')} style={{fontSize:16, padding:14}}>NEXT BOARD — 3 OF 4 →</Button>\n        <Button variant=\"secondary\" onClick={()=>go && go('HOME')}>Back to lobby</Button>\n      </div>\n    </div>\n  );\n}\n"}];
